class triflareFlareJS {
  getInfo() {
    return {
      id: 'triflareFlareJS',
      name: 'Flare.js',
      color1: '#6e59ff',
      color2: '#5745c7',
      color3: '#41339c',
      menuIconURI:
        'data:image/svg+xml;base64,',
      blocks: [
        {
          opcode: 'executeStatement',
          blockType: Scratch.BlockType.COMMAND,
          text: 'run javascript: [CODE]',
          arguments: {
            CODE: {
              type: Scratch.ArgumentType.STRING,
              defaultValue: 'for(let i=0; i<5; i++) { console.log("Loop " + i); }',
            },
          },
        },
        {
          opcode: 'evaluateExpression',
          blockType: Scratch.BlockType.REPORTER,
          text: 'evaluate javascript: [CODE]',
          arguments: {
            CODE: {
              type: Scratch.ArgumentType.STRING,
              defaultValue: 'Math.floor(Math.random() * 100)',
            },
          },
        },
        {
          opcode: 'evaluateBoolean',
          blockType: Scratch.BlockType.BOOLEAN,
          text: 'javascript: [CODE] is true?',
          arguments: {
            CODE: {
              type: Scratch.ArgumentType.STRING,
              defaultValue: '1 + 1 === 2',
            },
          },
        },
      ],
    };
  }

  executeStatement(args, util) {
    try {
      // We use new Function instead of eval to keep the scope clean,
      // but we pass in 'util' and 'Scratch' so you can interact with the engine if needed.
      const func = new Function('util', 'Scratch', args.CODE);
      func(util, Scratch);
    } catch (error) {
      console.error('Execution error:', error);
    }
  }

  evaluateExpression(args, util) {
    try {
      // Wrapping the code in a return statement allows evaluating expressions directly
      const func = new Function('util', 'Scratch', 'return (' + args.CODE + ');');
      const result = func(util, Scratch);

      // Scratch handles primitive types best, so we stringify objects
      if (typeof result === 'object' && result !== null) {
        return JSON.stringify(result);
      }

      // Return empty string instead of undefined to prevent UI artifacts in Scratch
      if (result === undefined) {
        return '';
      }

      return result;
    } catch (error) {
      console.error('Evaluation error:', error);
      return '';
    }
  }

  evaluateBoolean(args, util) {
    try {
      const func = new Function('util', 'Scratch', 'return (' + args.CODE + ');');
      // Force the result to be a strict Boolean for the Scratch engine
      return Boolean(func(util, Scratch));
    } catch (error) {
      console.error('Evaluation error:', error);
      return false;
    }
  }
}

Scratch.extensions.register(new triflareFlareJS());
